            "ref": "a",
            "attrs": {
              "parent_id": 20
            }
          },
          {
            "op": "create",
            "ref": "b",
            "attrs": {
              "parent_id": 20
            }
          },
          {
            "op": "create",
            "ref": "c",
            "attrs": {
              "parent_id": 20
            }
          }
