        "queries": [
          {
            "q": "item_status",
            "ref": "a"
          },
          {
            "q": "item_status",
            "ref": "b"
          },
          {
            "q": "item_status",
            "ref": "c"
          },
          {
            "q": "order_ids",
            "where": {
