    {
      "input": {
        "config": {
          "column": "position",
          "scope": "parent_id",
          "add_new_at": "top"
        },
        "operations": [
          {
            "op": "create",
            "ref": "a",
            "attrs": {
              "parent_id": 20
            }
          },
          {
            "op": "create",
            "ref": "b",
            "attrs": {
              "parent_id": 20
            }
          },
          {
            "op": "create",
            "ref": "c",
            "attrs": {
              "parent_id": 20
            }
          }
        ],
        "queries": [
          {
            "q": "order_ids",
            "where": {
              "parent_id": 20
            },
            "order": "position"
          },
          {
            "q": "item_status",
            "ref": "c"
          }
        ]
      },
      "expected_output": "ids=[3, 2, 1]\nposition=1 first=true last=false in_list=true"
    }
  ]
}

